    // Core default tasks based on project notes
    const defaultTasks = [
      {
        id: "task-1",
        title: "Build Walkthrough & v0 Teamfood",
        description: "Prepare coding agent updates and build walkthrough for Thursday's milestone sync.",
        assignee: "Mike Carcasole",
