    let isModalOpen = false;

    // Load active state
    async function loadBoardState() {
      let loadedData = null;

      // Sync endpoint load
      if (envId) {
        try {
          const res = await fetch(`/api/sync/${envId}/${syncKey}`);
          const json = await res.json();
          if (json && json.data) {
            loadedData = json.data;
          }
        } catch (err) {
          console.error("Failed to load synced state:", err);
        }
      }

      // Fallback local storage load
      if (!loadedData) {
        const local = localStorage.getItem("ollie_board_local");
        if (local) {
          try {
            loadedData = JSON.parse(local);
          } catch (err) {
            console.error("Failed to parse local storage board state:", err);
          }
        }
      }

      // Initial defaults fallback
      if (!loadedData || !loadedData.tasks || loadedData.tasks.length === 0) {
        loadedData = { tasks: defaultTasks };
        boardState = loadedData;
        saveBoardState();
      }

      // Only rerender if there is a real change and user is not editing inside a modal
      if (!isModalOpen) {
        const currentJson = JSON.stringify(boardState);
        const loadedJson = JSON.stringify(loadedData);

        if (currentJson !== loadedJson) {
          boardState = loadedData;
          renderBoard();
        }
      }
    }

    // Save active state
    async function saveBoardState() {
      localStorage.setItem("ollie_board_local", JSON.stringify(boardState));

      if (envId) {
        try {
          await fetch(`/api/sync/${envId}/${syncKey}`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ data: boardState })
          });
        } catch (err) {
          console.error("Failed to save synced state:", err);
        }
      }
    }

    // Populate dropdowns with real team members
    function populateDropdowns() {
      const filterSelect = document.getElementById("filterAssignee");
      const formSelect = document.getElementById("taskAssigneeInput");

      filterSelect.innerHTML = '<option value="all">All Assignees</option>';
      formSelect.innerHTML = '';

      teamMembers.forEach(member => {
        const filterOpt = document.createElement("option");
        filterOpt.value = member.name;
        filterOpt.textContent = `${member.name} (${member.role})`;
        filterSelect.appendChild(filterOpt);

        const formOpt = document.createElement("option");
        formOpt.value = member.name;
        formOpt.textContent = `${member.name} (${member.role})`;
        formSelect.appendChild(formOpt);
      });
    }

    // Reset to Context Default Tasks
    function resetToDefaults() {
      if (confirm("Reset current board tasks to the Project Ollie baseline roadmap?")) {
        boardState = { tasks: JSON.parse(JSON.stringify(defaultTasks)) };
        saveBoardState();
        renderBoard();
      }
    }

    // Drag and Drop State Management
    let draggedTaskId = null;

    function handleDragStart(e, id) {
      draggedTaskId = id;
      e.dataTransfer.setData("text/plain", id);
      setTimeout(() => {
        e.target.classList.add("dragging");
      }, 0);
    }

    function handleDragEnd(e) {
      e.target.classList.remove("dragging");
    }

    // Allow drop
    function handleDragOver(e) {
      e.preventDefault();
    }

    function handleDragEnter(e, columnId) {
      e.preventDefault();
      const col = document.getElementById(`col-${columnId}`);
      if (col) col.classList.add("drag-over");
    }

    function handleDragLeave(e, columnId) {
      const col = document.getElementById(`col-${columnId}`);
      if (col) col.classList.remove("drag-over");
    }

    function handleDrop(e, columnId) {
      e.preventDefault();
      const col = document.getElementById(`col-${columnId}`);
      if (col) col.classList.remove("drag-over");

      if (draggedTaskId) {
        const taskIndex = boardState.tasks.findIndex(t => t.id === draggedTaskId);
        if (taskIndex !== -1 && boardState.tasks[taskIndex].status !== columnId) {
          boardState.tasks[taskIndex].status = columnId;
          saveBoardState();
          renderBoard();
        }
      }
    }

    // Modal Control
    function openAddTaskModal(status = 'to-do') {
      isModalOpen = true;
      document.getElementById("modalTitle").innerText = "Add New Task";
      document.getElementById("editTaskId").value = "";
      document.getElementById("taskForm").reset();
      document.getElementById("taskStatusInput").value = status;

      const today = new Date().toISOString().split('T')[0];
      document.getElementById("taskDueDateInput").value = today;

      document.getElementById("taskModal").classList.remove("hidden");
    }

    function openEditTaskModal(id) {
      isModalOpen = true;
      const task = boardState.tasks.find(t => t.id === id);
      if (!task) return;

      document.getElementById("modalTitle").innerText = "Edit Task";
      document.getElementById("editTaskId").value = task.id;
      document.getElementById("taskTitleInput").value = task.title;
      document.getElementById("taskDescriptionInput").value = task.description;
      document.getElementById("taskAssigneeInput").value = task.assignee;
      document.getElementById("taskPriorityInput").value = task.priority;
      document.getElementById("taskTagInput").value = task.tag;
      document.getElementById("taskDueDateInput").value = task.dueDate || "";
      document.getElementById("taskStatusInput").value = task.status;

      document.getElementById("taskModal").classList.remove("hidden");
    }

    function closeModal() {
      document.getElementById("taskModal").classList.add("hidden");
      isModalOpen = false;
    }

    function handleFormSubmit(e) {
      e.preventDefault();

      const id = document.getElementById("editTaskId").value;
      const title = document.getElementById("taskTitleInput").value.trim();
      const description = document.getElementById("taskDescriptionInput").value.trim();
      const assignee = document.getElementById("taskAssigneeInput").value;
      const priority = document.getElementById("taskPriorityInput").value;
      const tag = document.getElementById("taskTagInput").value;
      const dueDate = document.getElementById("taskDueDateInput").value;
      const status = document.getElementById("taskStatusInput").value;

      if (!title) return;

      if (id) {
        const task = boardState.tasks.find(t => t.id === id);
        if (task) {
          task.title = title;
          task.description = description;
          task.assignee = assignee;
          task.priority = priority;
          task.tag = tag;
          task.dueDate = dueDate;
          task.status = status;
        }
      } else {
        const newTask = {
          id: "task-" + Date.now(),
          title,
          description,
          assignee,
          priority,
          tag,
          dueDate,
          status
        };
        boardState.tasks.push(newTask);
      }

      closeModal();
      saveBoardState();
      renderBoard();
    }

    function deleteTask(id) {
      if (confirm("Are you sure you want to delete this task?")) {
        boardState.tasks = boardState.tasks.filter(t => t.id !== id);
        saveBoardState();
        renderBoard();
      }
    }

    // Rendering core columns and cards
    function renderBoard() {
      const searchQuery = document.getElementById("searchBar").value.toLowerCase();
      const filterAssignee = document.getElementById("filterAssignee").value;
      const filterPriority = document.getElementById("filterPriority").value;
      const filterTag = document.getElementById("filterTag").value;

      const columns = {
        "to-do": document.getElementById("tasks-to-do"),
        "in-progress": document.getElementById("tasks-in-progress"),
        "review": document.getElementById("tasks-review"),
        "done": document.getElementById("tasks-done")
      };

      Object.values(columns).forEach(col => {
        if (col) col.innerHTML = "";
      });

      const filteredTasks = boardState.tasks.filter(task => {
        const matchesSearch = task.title.toLowerCase().includes(searchQuery) || 
                              task.description.toLowerCase().includes(searchQuery);
        const matchesAssignee = filterAssignee === "all" || task.assignee === filterAssignee;
        const matchesPriority = filterPriority === "all" || task.priority === filterPriority;
        const matchesTag = filterTag === "all" || task.tag === filterTag;

        return matchesSearch && matchesAssignee && matchesPriority && matchesTag;
      });

      filteredTasks.forEach(task => {
        const col = columns[task.status];
        if (!col) return;

        const card = document.createElement("div");
        card.className = `task-card`;
        card.draggable = true;
        card.setAttribute("ondragstart", `handleDragStart(event, '${task.id}')`);
        card.setAttribute("ondragend", "handleDragEnd(event)");

        const initials = getInitials(task.assignee);
        const avatarColor = getAvatarColor(task.assignee);

        card.innerHTML = `
          <div class="card-header">
            <span class="card-tag tag-${task.tag.toLowerCase().replace(" ", "-")}">${task.tag}</span>
            <span class="card-priority prio-${task.priority.toLowerCase()}">${task.priority}</span>
          </div>
          <h3 class="card-title">${escapeHTML(task.title)}</h3>
          <p class="card-desc">${escapeHTML(task.description)}</p>
          <div class="card-footer">
            <div class="card-assignee" title="${escapeHTML(task.assignee)}">
              <div class="avatar" style="background-color: ${avatarColor}">${initials}</div>
              <span class="assignee-name">${escapeHTML(task.assignee)}</span>
            </div>
            <div class="card-actions">
              <button class="icon-btn" onclick="openEditTaskModal('${task.id}')" title="Edit Task">
                <span class="material-symbols-outlined" style="font-size: 16px;">edit</span>
              </button>
              <button class="icon-btn delete-btn" onclick="deleteTask('${task.id}')" title="Delete Task">
                <span class="material-symbols-outlined" style="font-size: 16px;">delete</span>
              </button>
            </div>
          </div>
          ${task.dueDate ? `
            <div class="card-due-date">
              <span class="material-symbols-outlined" style="font-size: 13px;">calendar_today</span>
              <span>Due: ${task.dueDate}</span>
            </div>
          ` : ''}
        `;

        col.appendChild(card);
      });

      updateStats();
    }

    // Helper functions
    function getInitials(name) {
      if (!name) return "??";
      if (name.includes("Agent")) {
        return "AI";
      }
      const parts = name.split(" ");
      if (parts.length >= 2) {
        return (parts[0][0] + parts[1][0]).toUpperCase();
      }
      return name.slice(0, 2).toUpperCase();
    }

    function getAvatarColor(name) {
      if (name.includes("Agent")) {
        return "#5f6368";
      }
      const colors = [
        "#1a73e8", "#34a853", "#f9ab00", "#ea4335", "#a142f4", 
        "#00acc1", "#ff7043", "#689f38", "#455a64", "#c2185b"
      ];
      let hash = 0;
      for (let i = 0; i < name.length; i++) {
        hash = name.charCodeAt(i) + ((hash << 5) - hash);
      }
      const index = Math.abs(hash) % colors.length;
      return colors[index];
    }

    function escapeHTML(str) {
      if (!str) return "";
      return str.replace(/[&<>'"]/g, 
        tag => ({
          '&': '&amp;',
          '<': '&lt;',
          '>': '&gt;',
          "'": '&#39;',
          '"': '&quot;'
        }[tag] || tag)
      );
    }

    function updateStats() {
      const counts = { "to-do": 0, "in-progress": 0, "review": 0, "done": 0 };
      boardState.tasks.forEach(t => {
        if (counts[t.status] !== undefined) {
          counts[t.status]++;
        }
      });

      document.getElementById("count-to-do").innerText = counts["to-do"];
      document.getElementById("count-in-progress").innerText = counts["in-progress"];
      document.getElementById("count-review").innerText = counts["review"];
      document.getElementById("count-done").innerText = counts["done"];

      const total = boardState.tasks.length;
      const completed = counts["done"];
      const progressPercent = total > 0 ? Math.round((completed / total) * 100) : 0;

      document.getElementById("progress-bar-fill").style.width = `${progressPercent}%`;
      document.getElementById("progress-text").innerText = `${completed} of ${total} tasks completed (${progressPercent}%)`;
    }

    // Escape listener for modals
    window.addEventListener('keydown', (e) => {
      if (e.key === 'Escape') {
        closeModal();
      }
    });

    // Run Initializer
    populateDropdowns();
    loadBoardState().then(() => {
      renderBoard();
    });

    // Sync polling (every 2 seconds)
    if (envId) {
      setInterval(loadBoardState, 2000);
    }
  </script>
